struct Point {
    int x, y;
    bool valid;
    Point(int X = 0, int Y = 0, bool valid_ = 1)
    :x(X), y(Y), valid(valid_){}
    friend void print_point(Point const &pt,...) {
        va_list args;
        va_start(args, pt);
        auto out = va_arg(args, FILE *);
        if (out == NULL) {
            out = stdout;
        }
        fprintf(out, "%s %d %d %d\n", 
            (pt.valid? "" : "Invalid "), pt.x, pt.y,
            pt.x * pt.x + pt.y * pt.y);
        va_end(args);
    }
};

int main8() {
    Point const A(1,3);
    Point const B(2,4, 1);
    Point const *L[] = {&A, &B};
    auto* out = fopen("output.txt", "w");
    for (auto&& pt : L) {
        print_point(*pt, out);
    }
    fclose(out);
    return 0;
}

