struct Clock {
    int mins;
    void addMin(int n) {
        mins += n;
        mins %= 1440;
    }

    time getTime() {
        time t;
        t.hour = mins / 60;
        t.minute = mins - t.hour * 60;
        t.second = mins / 1440.0;  
        return t;
    }
};

