#include <iostream>

using namespace std;
enum states {start, ready, finish};
class StateMachine
{
    private:
        states State;
        int Data = 0;
    public:
        void start(int Data)
        {
            this->State = start;
            this->Data = Data;
        }
        void go();
        states getstate()
        {
            return this->State;
        }
};
void StateMachine::go()
{
    if(State == start)
    {

        State = ready;
        Data = Data*100;
    }
    else if( State == ready)
    {

        State = finish;
    }
}
int main()
{
    StateMachine s;
    s.start(10);
    cout << "State before action: " << s.getstate() << endl;
    s.go();
    cout << "State after action1: " << s.getstate() << endl;
    cout << "Data is changed to " << s.Data << endl;
    s.go();
    cout << "State after action2: " << s.getstate() << endl;
    s.go();
    cout << "State after action3: " << s.getstate() << endl;
